verilog:
module counter(input clk, input rst, output reg [7:0] count);
always @(posedge clk or posedge rst)
    if (rst) count <= 0;
    else count <= count + 1;
endmodule

module fifo(input clk, input rst, input [7:0] din, input wr, 
            output reg [7:0] dout, input rd, output full, output empty);
reg [7:0] mem[0:15];
reg [3:0] wr_ptr, rd_ptr;
assign full = (wr_ptr == ~rd_ptr);
assign empty = (wr_ptr == rd_ptr);
always @(posedge clk) begin
    if (wr && !full) mem[wr_ptr] <= din;
    if (rd && !empty) dout <= mem[rd_ptr];
end
endmodule

module alu(input [7:0] a, input [7:0] b, input [2:0] op, 
            output reg [7:0] result);
always @(*)
    case(op)
        0: result = a + b;
        1: result = a - b;
        2: result = a & b;
        3: result = a | b;
        default: result = 0;
    endcase
endmodule
